import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Login.css";

export default function Login() {
  const navigate = useNavigate();
  const [role, setRole] = useState("");

  // ✅ Hardcoded Admin & HR Users
  const allowedAdmins = [
    { email: "admin@university.edu", password: "admin123" }
  ];

  const allowedHRs = [
    { email: "hr@company.com", password: "hr2025" }
  ];

  function handleLogin(e) {
    e.preventDefault();

    const selectedRole = e.target.role.value;
    const password = e.target.password.value.trim();

    if (selectedRole === "student") {
      const roll = e.target.rollno.value.trim();
      const savedRoll = localStorage.getItem("rollNumber") || "";
      const savedPass = localStorage.getItem("password");
      const savedRole = localStorage.getItem("role");

      if (roll === savedRoll && password === savedPass && savedRole === "student") {
        alert("Login successful as Student!");
        navigate("/dashboard");
      } else {
        alert("Invalid student credentials");
      }

    } else if (selectedRole === "admin") {
      const email = e.target.email.value.trim();
      const found = allowedAdmins.find(user => user.email === email && user.password === password);

      if (found) {
        localStorage.setItem("userRole", "admin");
        alert("Admin login successful!");
        navigate("/dashboard");
      } else {
        alert("Invalid Admin credentials");
      }

    } else if (selectedRole === "hr") {
      const email = e.target.email.value.trim();
      const found = allowedHRs.find(user => user.email === email && user.password === password);

      if (found) {
        localStorage.setItem("userRole", "hr");
        alert("HR login successful!");
        navigate("/dashboard");
      } else {
        alert("Invalid HR credentials");
      }
    }
  }

  return (
    <div className="split-layout">
      <div className="left-panel">
        <h1>🎓 Campus Connect</h1>
        <div className="tagline-box">
          <h2>Wide College Network</h2>
          <p>Favorite Space To Connect!</p>
        </div>
        <img
          src="https://img.freepik.com/premium-vector/graduation-students_1214-321.jpg"
          alt="Graduates"
          className="illustration"
        />
      </div>

      <div className="right-panel">
        <div className="form-box shadow-card">
          <div className="tabs">
            <Link to="/login" className="tab active">Login</Link>
            <Link to="/register" className="tab">Signup</Link>
          </div>

          <h2>Login</h2>
          <form onSubmit={handleLogin}>
            {role === "student" && (
              <>
                <label>University Roll Number</label>
                <input name="rollno" type="text" placeholder="Enter your roll number" required />
              </>
            )}

            {(role === "admin" || role === "hr") && (
              <>
                <label>Email</label>
                <input name="email" type="email" placeholder="Enter your email" required />
              </>
            )}

            <label>Password</label>
            <input name="password" type="password" placeholder="Enter your password" required />

            <label>Role</label>
            <select name="role" required value={role} onChange={(e) => setRole(e.target.value)}>
              <option value="">-- Select Role --</option>
              <option value="student">Student</option>
              <option value="admin">Admin</option>
              <option value="hr">HR</option>
            </select>

            <button type="submit">Login</button>
          </form>

          <p className="signup-cta">
            New to Campus Connect? <Link to="/register"><strong>Signup</strong></Link>
          </p>
        </div>
      </div>
    </div>
  );
}
